import sailpoint.tools.Util;
import sailpoint.object.Identity;

import java.util.ArrayList;
import java.util.List;

log.error("Entered into Workflow");
log.error("Identity List    " + identityList);
log.error("User Count List  " + userCount);
log.error("Counts           " + Util.nullSafeSize(Util.csvToList(identityList)));
log.error("ApplicationName  " + applicationName);
log.error("Operation        " + operation);

List  errorsList = new ArrayList();

// Validate identityList
if (Util.isNullOrEmpty(identityList)) {

log.error("Step =====   Util.isNullOrEmpty(identityList)");


errorsList.add("Please provide at least one user name. The list cannot be empty.");

errorsList.add("Enter user names in CSV format, for example: TestUser1, TestUser2.");

} else {

List csvToList = Util.csvToList(identityList);

log.error("Step =====  csvToList"+csvToList);

if (Util.nullSafeSize(csvToList) > 0) {
for (String eachIdName : csvToList) {

log.error("Step =====   eachIdName"+eachIdName);

if (context.getObjectByName(Identity.class,eachIdName) == null) {

log.error("Step =====   eachname null");
errorsList.add("The user '" + eachIdName + "' was not found. Please check the spelling or ensure the user exists in SailPoint.");
}
}
}
}
log.error("Step =====   Before Operation");

// Validate operation
if (Util.isNullOrEmpty(operation)) {

log.error("Step =====   Util.isNullOrEmpty(operation)");
errorsList.add("Please select an action. Allowed actions are 'lock' or 'unlock'.");
} else {
log.error("Before every check of Lock or Unlock");

if (!("lock".equalsIgnoreCase(operation) || "unlock".equalsIgnoreCase(operation))) {

log.error("Step =====   Operation Checks");
errorsList.add("Invalid action: '" + operation + "'. Allowed actions are 'lock' or 'unlock'.");
}
}
log.error("Step =====   Before Application");
// Validate applicationName
if (Util.isNullOrEmpty(applicationName)) {
log.error("Step =====  (Util.isNullOrEmpty(applicationName))");
errorsList.add("Please specify the application. Allowed values are 'Active Directory' or 'All'.");
} else {
if (!("AD".equalsIgnoreCase(applicationName) || "All".equalsIgnoreCase(applicationName))) {

log.error("Step =====   AD or all");
errorsList.add("Invalid application: '" + applicationName + "'. Allowed values are 'Active Directory' or 'All'.");
}
}

if (!errorsList.isEmpty()) {
log.error("Validation errors: " + errorsList);
wfcase.addMessage(String.join("\n", errorsList)); 
}

import sailpoint.tools.Util;
import sailpoint.object.ProvisioningPlan;
import sailpoint.object.Link;
import sailpoint.api.IdentityService;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.Identity;
import sailpoint.object.Application;
import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
import sailpoint.object.Filter;
import sailpoint.object.QueryOptions;
import java.util.Iterator;
import sailpoint.api.SailPointContext;

String adCIBeg= null;
Identity objectByName = context.getObjectByName(Identity.class, identityName);

ProvisioningPlan plan = new ProvisioningPlan();

Filter filter = Filter.eq("identity.name", identityName);
QueryOptions qo = new QueryOptions();
qo.add(filter);
qo.setCloneResults(true);

Iterator search = context.search(Link.class,qo,"id");

while(search.hasNext()) {

String linkId= (String) search.next()[0];
Link objectById = context.getObjectById(Link.class, linkId);

if(objectById.getApplication().isAuthoritative())continue;
if(operation.equalsIgnoreCase("Lock")) {
if(objectById.isDisabled())continue;

plan.add( new AccountRequest(AccountRequest.Operation.Disable, objectById.getApplicationName(), null, objectById.getNativeIdentity()));

}

else if(operation.equalsIgnoreCase("unLock")) {

if(!objectById.isDisabled())continue;

if(objectById.getApplicationName().equalsIgnoreCase(adCIBeg))continue;  

plan.add( new AccountRequest(AccountRequest.Operation.Enable, objectById.getApplicationName(), null, objectById.getNativeIdentity()));

}
}

log.error("BuilPlan Step ======= "+plan.toXml()); 
return plan;
